INSERT INTO `party_ideology` VALUES ('50PLUS','Belangenpartij voor ouderen; richt zich op pensioenen, koopkracht en zorg voor senioren.','50PLUS'),('BBB','Agrarisch-populistisch; verdedigt boerenbelangen en pleit voor minder afstand tussen burger en politiek.','BBB'),('BIJ1','Radicaal-progressief; legt nadruk op antiracisme, gelijkwaardigheid en sociale rechtvaardigheid.','BIJ1'),('BVNL','Rechts-liberaal; wil minder overheid, lagere belastingen en meer nationale soevereiniteit.','BVNL / Groep Van Haga'),('CDA','Christendemocratisch; combineert solidariteit, rentmeesterschap en gedeelde verantwoordelijkheid.','CDA'),('CHRISTENUNIE','Christelijk-sociaal; combineert sociale zorg met ethisch conservatieve standpunten.','ChristenUnie'),('D66','Sociaal-liberaal; sterk gericht op onderwijs, democratische vernieuwing en Europese samenwerking.','D66'),('DENK','Progressief en multicultureel; focust op inclusiviteit, anti-discriminatie en gelijke kansen.','DENK'),('FVD','Rechts-conservatief en eurosceptisch; benadrukt nationale soevereiniteit en traditionele waarden.','Forum voor Democratie'),('GROENLINKS/PVDA','Progressief en sociaal-democratisch; focus op klimaat, bestaanszekerheid en sociale gelijkheid.','GROENLINKS / Partij van de Arbeid (PvdA)'),('JA21','Conservatief-liberaal; voor streng migratiebeleid, economische vrijheid en een kleinere overheid.','JA21'),('LEF - VOOR DE NIEUWE GENERATIE','Jong-progressief; richt zich op de stem van nieuwe generaties, bestuurlijke vernieuwing en toekomstgericht beleid.','LEF - Voor de Nieuwe Generatie'),('LP','Libertarisch; wil maximale individuele vrijheid en minimale overheidsbemoeienis.','LP (Libertaire Partij)'),('NIEUW SOCIAAL CONTRACT','Sociaal-conservatief; legt nadruk op goed bestuur, bestaanszekerheid en herstel van vertrouwen in de overheid.','Nieuw Sociaal Contract'),('NL PLAN','Pragmatisch-populistisch; richt zich op praktische oplossingen voor maatschappelijke en economische problemen.','Nederland met een PLAN'),('PARTIJ VOOR DE DIEREN','Ecologisch en progressief; dierenrechten, natuur en duurzaamheid staan centraal.','Partij voor de Dieren'),('PARTIJVDSPORT','Sportgericht en maatschappelijk; zet sport, beweging en vitaliteit centraal in beleid.','PartijvdSport'),('PIRATENPARTIJ - DE GROENEN','Digitaal-progressief en groen; richt zich op privacy, transparantie, duurzaamheid en burgerrechten.','Piratenpartij - De Groenen'),('POLITIEKE PARTIJ VOOR BASISINKOMEN','Sociaal-progressief; pleit voor een onvoorwaardelijk basisinkomen en bestaanszekerheid.','Politieke Partij voor Basisinkomen'),('PVV','Rechts-populistisch; sterk gericht op anti-immigratie, nationale identiteit en kritiek op islam en EU.','PVV (Partij voor de Vrijheid)'),('SAMEN VOOR NEDERLAND','Nationalistisch-conservatief; benadrukt nationale identiteit, gemeenschapszin en maatschappelijke samenhang.','Samen voor Nederland'),('SGP','Orthodox-protestants en conservatief; baseert haar politiek op Bijbelse normen en waarden.','Staatkundig Gereformeerde Partij (SGP)'),('SP','Socialistisch; strijdt tegen ongelijkheid en voor een sterke publieke sector.','SP (Socialistische Partij)'),('SPLINTER','Progressief en inclusief; legt nadruk op representatie, gelijke kansen en sociale rechtvaardigheid.','Splinter'),('VOLT','Pan-Europees progressief; wil meer Europese samenwerking, innovatie en duurzaamheid.','Volt'),('VVD','Liberaal-conservatief; legt nadruk op vrije markt, individuele verantwoordelijkheid en economische groei.','VVD');
/*!40000 ALTER TABLE `party_ideology` ENABLE KEYS */;
